  }
  OPTIONAL {
    ?country p:P3864 ?maleStmt .
    ?maleStmt ps:P3864 ?maleRate ; pq:P21 wd:Q6581072 .
    FILTER(xsd:double(?maleRate) > 0)
  }
  OPTIONAL {
    ?country p:P3864 ?femaleStmt .
    ?femaleStmt ps:P3864 ?femaleRate ; pq:P21 wd:Q6571072 .
    FILTER(xsd:double(?femaleRate) > 0)
  }
}

SELECT ?author ?authorLabel WHERE {
  wd:Q4417649 wdt:P50 ?author .
  OPTIONAL {
    ?author rdfs:label ?authorLabel .
    FILTER(LANG(?authorLabel) = "en")
  }
}

SELECT DISTINCT ?secretary ?label WHERE {
  ?secretary p:P39 ?statement .
  ?statement ps:P39 wd:Q642859 ; pq:P580 ?start ; pq:P582 ?end .
  FILTER(xsd:dateTime(?start) <= "2017-12-31T23:59:59Z" ^^ xsd:dateTime && xsd:dateTime(?end) >= "2017-01-01T00:00:00Z" ^^ xsd:dateTime)
  .
  OPTIONAL {
    ?secretary rdfs:label ?label .
    FILTER(LANG(?label) = "en")
  }
}
ORDER BY ?start

